mapper.sql:
WHERE tb_group.id is not null
AND tb_group.deleted = #{deleted}
AND tb_group.group_name LIKE CONCAT('%', #{groupName}, '%')

AND user_space.status = #{status}
AND user_space.role = #{role}

mapper.select:
SELECT DISTINCT tb_group.id FROM tb_group JOIN space ON tb_group.id = space.group_id JOIN user_space ON space.id = user_space.space_id
AND space.deleted = false AND user_space.user_id = #{reqUserId}
AND #{cursor} > tb_group.id AND tb_group.id > #{cursor}
ORDER BY tb_group.id DESC ASC
LIMIT 0, #{perPage}
